#include <stdio.h>
#include <string.h>

int main(void) {
    char str[101];
    fgets(str, sizeof(str), stdin);

    int len = strlen(str);
    if (str[len - 1] == '\n') {
        str[len - 1] = '\0';
        len--;
    }

    for (int i = len - 1; i >= 0; i--) {
        printf("%c", str[i]);
    }
    printf("\n");

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char str[101];
    fgets(str, sizeof(str), stdin);

    int vowels = 0, consonants = 0;

    for (int i = 0; str[i] != '\0'; i++) {
        char c = tolower(str[i]);
        if (isalpha(str[i])) {
            if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') {
                vowels++;
            } else {
                consonants++;
            }
        }
    }

    printf("%d %d\n", vowels, consonants);

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char str[201];
    fgets(str, sizeof(str), stdin);

    char longest[201] = "";
    int maxLen = 0;
    char currentWord[201] = "";
    int currentLen = 0;

    for (int i = 0; str[i] != '\0'; i++) {
        if (isalpha(str[i])) {
            currentWord[currentLen] = str[i];
            currentLen++;
        } else {
            if (currentLen > maxLen) {
                maxLen = currentLen;
                for (int j = 0; j < currentLen; j++) {
                    longest[j] = currentWord[j];
                }
                longest[currentLen] = '\0';
            }
            currentLen = 0;
        }
    }

    if (currentLen > maxLen) {
        for (int j = 0; j < currentLen; j++) {
            longest[j] = currentWord[j];
        }
        longest[currentLen] = '\0';
    }

    printf("%s\n", longest);

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char str[101];
    fgets(str, sizeof(str), stdin);

    char clean[101];
    int cleanLen = 0;

    for (int i = 0; str[i] != '\0'; i++) {
        if (isalpha(str[i])) {
            clean[cleanLen] = tolower(str[i]);
            cleanLen++;
        }
    }
    clean[cleanLen] = '\0';

    int isPalin = 1;
    for (int i = 0; i < cleanLen / 2; i++) {
        if (clean[i] != clean[cleanLen - 1 - i]) {
            isPalin = 0;
            break;
        }
    }

    printf("%s\n", isPalin ? "yes" : "no");

    return 0;
}

#include <stdio.h>
#include <string.h>

int main(void) {
    char str[101];
    fgets(str, sizeof(str), stdin);

    char result[101];
    int resultLen = 0;

    for (int i = 0; str[i] != '\0'; i++) {
        int found = 0;
        for (int j = 0; j < resultLen; j++) {
            if (str[i] == result[j]) {
                found = 1;
                break;
            }
        }
        if (!found) {
            result[resultLen] = str[i];
            resultLen++;
        }
    }
    result[resultLen] = '\0';

    printf("%s", result);

    return 0;
}

