#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char str[101];
    fgets(str, sizeof(str), stdin);

    int startOfWord = 1;

    for (int i = 0; str[i] != '\0'; i++) {
        if (isalpha(str[i])) {
            if (startOfWord) {
                printf("%c", toupper(str[i]));
                startOfWord = 0;
            } else {
                printf("%c", tolower(str[i]));
            }
        } else {
            printf("%c", str[i]);
            startOfWord = 1;
        }
    }

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char str[101];
    fgets(str, sizeof(str), stdin);

    char chars[27];
    int counts[27] = {0};
    int charCount = 0;

    for (int i = 0; str[i] != '\0'; i++) {
        if (isalpha(str[i])) {
            char c = tolower(str[i]);
            int found = 0;
            for (int j = 0; j < charCount; j++) {
                if (chars[j] == c) {
                    counts[j]++;
                    found = 1;
                    break;
                }
            }
            if (!found) {
                chars[charCount] = c;
                counts[charCount] = 1;
                charCount++;
            }
        }
    }

    for (int i = 0; i < charCount; i++) {
        printf("%c %d\n", chars[i], counts[i]);
    }

    return 0;
}

#include <stdio.h>
#include <string.h>

int main(void) {
    char source[101];
    char pattern[51];
    char replacement[51];

    fgets(source, sizeof(source), stdin);
    fgets(pattern, sizeof(pattern), stdin);
    fgets(replacement, sizeof(replacement), stdin);

    int slen = strlen(source);
    if (source[slen - 1] == '\n') source[slen - 1] = '\0';

    int plen = strlen(pattern);
    if (pattern[plen - 1] == '\n') pattern[plen - 1] = '\0';

    int rlen = strlen(replacement);
    if (replacement[rlen - 1] == '\n') replacement[rlen - 1] = '\0';

    char result[301] = "";
    int resultLen = 0;

    for (int i = 0; source[i] != '\0'; i++) {
        int match = 1;
        for (int j = 0; j < plen && source[i + j] != '\0'; j++) {
            if (source[i + j] != pattern[j]) {
                match = 0;
                break;
            }
        }

        if (match) {
            for (int j = 0; j < rlen; j++) {
                result[resultLen] = replacement[j];
                resultLen++;
            }
            i += plen - 1;
        } else {
            result[resultLen] = source[i];
            resultLen++;
        }
    }
    result[resultLen] = '\0';

    printf("%s\n", result);

    return 0;
}

#include <stdio.h>
#include <string.h>

int main(void) {
    char strA[51];
    char strB[51];

    fgets(strA, sizeof(strA), stdin);
    fgets(strB, sizeof(strB), stdin);

    int lenA = strlen(strA);
    if (strA[lenA - 1] == '\n') strA[lenA - 1] = '\0';
    lenA = strlen(strA);

    int lenB = strlen(strB);
    if (strB[lenB - 1] == '\n') strB[lenB - 1] = '\0';
    lenB = strlen(strB);

    char result[101] = "";
    int resultLen = 0;

    int i = 0, j = 0;
    while (i < lenA && j < lenB) {
        result[resultLen] = strA[i];
        resultLen++;
        i++;
        result[resultLen] = strB[j];
        resultLen++;
        j++;
    }

    while (i < lenA) {
        result[resultLen] = strA[i];
        resultLen++;
        i++;
    }

    while (j < lenB) {
        result[resultLen] = strB[j];
        resultLen++;
        j++;
    }

    result[resultLen] = '\0';

    printf("%s\n", result);

    return 0;
}
